      items: batchItems,
      bureau,
      itemType,
      recommendedRound: round,
      priority,
      legalBasis,
    });
  }

  // Sort batches by priority
  batches.sort((a, b) => {
    const priorityOrder = { high: 0, medium: 1, low: 2 };
