import { Users, FileText, Target, CheckCircle } from 'lucide-react';

export interface Client {
  id: string;
  first_name: string | null;
  last_name: string | null;
  email: string | null;
  phone: string | null;
  status: string;
}

export interface NegativeItem {
  id: string;
  creditor_name: string;
  original_creditor: string | null;
  account_number?: string | null;
  item_type: string;
  amount: number | null;
  date_reported: string | null;
  date_of_first_delinquency?: string | null;
  bureau: string | null;
  bureaus?: string[];
  on_transunion?: boolean;
  on_experian?: boolean;
  on_equifax?: boolean;
  transunion_date?: string | null;
  experian_date?: string | null;
  equifax_date?: string | null;
  transunion_status?: string | null;
  experian_status?: string | null;
  equifax_status?: string | null;
  account_type?: string | null;
  payment_history_grid?: Record<string, Record<string, string>> | null;
  risk_severity: string;
  recommended_action: string | null;
}

export interface PersonalInfoItem {
  id: string;
  bureau: string;
  type: string;
  value: string;
}

export interface InquiryItem {
  id: string;
  creditor_name: string;
  bureau: string | null;
  inquiry_date?: string | null;
  inquiry_type?: string | null;
  is_past_fcra_limit?: boolean | null;
  days_since_inquiry?: number | null;
}

export interface ItemDisputeInstruction {
  itemId: string;
  instructionType: 'preset' | 'custom';
  presetCode?: string;
  customText?: string;
}

export interface ReasonCode {
  code: string;
  label: string;
  description: string;
  methodologyFit?: string[];
  strength?: string;
}

export interface DisputeType {
  code: string;
  label: string;
}

export interface TriageQuickAction {
  id: string;
  label: string;
  description: string;
  itemIds: string[];
  count: number;
  bureau?: string;
  itemType?: string;
}

export interface EvidenceDocument {
  id: string;
  file_name: string;
  file_type: string;
  file_url: string;
  created_at: string;
}

export interface Methodology {
  code: string;
  name: string;
  description: string;
  roundRange: number[];
  targetRecipients: string[];
  bestFor: string[];
  successIndicators: string[];
}

export interface AIAnalysisResult {
  itemId: string;
  creditorName: string;
  itemType: string;
  suggestedMethodology: string;
  autoReasonCodes: string[];
  metro2Violations: string[];
  fcraIssues: string[];
  confidence: number;
  analysisNotes: string;
}

export interface AIAnalysisSummary {
  itemCount: number;
  recommendedMethodology: string;
  allReasonCodes: string[];
  recommendedReasonCodes?: string[];
  allMetro2Violations: string[];
  allFcraIssues: string[];
  averageConfidence: number;
  analysisNotes: string;
}

export type DisputeItemKind = 'tradeline' | 'personal' | 'inquiry';

export interface DisputeItemPayload {
  id: string;
  kind: DisputeItemKind;
  bureau?: string | null;
  creditorName?: string;
  originalCreditor?: string | null;
  accountNumber?: string | null;
  itemType?: string;
  amount?: number | null;
  value?: string;
  inquiryDate?: string | null;
  inquiryType?: string | null;
  isPastFcraLimit?: boolean | null;
  daysSinceInquiry?: number | null;
  riskSeverity?: string | null;
}

export interface GeneratedLetter {
  id: string;
  bureau: string;
  itemId: string;
  itemIds?: string[];
  items?: DisputeItemPayload[];
  itemKind?: DisputeItemKind;
  content: string;
  combined: boolean;
